from sentence_transformers import SentenceTransformer
import numpy as np
import hashlib, os

class RAGEmbedder:
    def __init__(self, model_name="all-MiniLM-L6-v2", cache_dir=".emb_cache"):
        self.model = SentenceTransformer(model_name)
        self.cache_dir = cache_dir
        os.makedirs(cache_dir, exist_ok=True)
        self._cache = {}

    def _hash(self, text: str) -> str:
        return hashlib.sha256(text.encode()).hexdigest()[:16]

    def encode_single(self, text: str) -> np.ndarray:
        key = self._hash(text)
        if key in self._cache:
            return self._cache[key]
        emb = self.model.encode(text, normalize_embeddings=True)
        self._cache[key] = emb
        return emb

    def encode_batch(self, texts: list[str]) -> np.ndarray:
        return self.model.encode(texts, normalize_embeddings=True, batch_size=256)

    def save_index(self, embeddings, path="index.npy"):
        np.save(os.path.join(self.cache_dir, path), embeddings)

    def load_index(self, path="index.npy") -> np.ndarray:
        return np.load(os.path.join(self.cache_dir, path))

embedder = RAGEmbedder()
docs = ["AI is transforming healthcare", "Python powers data pipelines"]
index = embedder.encode_batch(docs)
embedder.save_index(index)
print(f"Saved index: {index.shape}")
print(f"Cache dir: {embedder.cache_dir}")
